"use client";

/**
 * Magellan Dial — canonical semicircular gauge primitive.
 *
 * One viewBox unit == one real pixel (chart text never balloons; responsive-charts spec §2).
 * Animated needle sweep on mount. Honors `prefers-reduced-motion`.
 *
 * Anatomy: a 180° arc from 0% (left) to 100% (right). You can paint a target
 * zone and/or an alert zone over the base arc. The needle sweeps to `value`'s
 * position within [min,max]. The center readout shows formatted value + unit.
 */

import { useEffect, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export type DialState = "ok" | "warn" | "alert";

export type DialZone = {
  /** start in 0..100 percent of the arc */
  startPct: number;
  /** end in 0..100 percent of the arc */
  endPct: number;
  /** css color string (stroke) */
  color: string;
};

export type DialTick = {
  /** position in 0..100 percent of the arc */
  pct: number;
  label?: string;
  major?: boolean;
};

type Props = {
  /** current value */
  value: number;
  /** range start (corresponds to 0% on the arc) */
  min: number;
  /** range end (corresponds to 100% on the arc) */
  max: number;
  /** colored zones painted over the base arc, in paint order */
  zones?: DialZone[];
  /** tick marks + labels at fixed % positions */
  ticks?: DialTick[];
  /** state — drives needle/pivot color and readout color */
  state?: DialState;
  /** displayed in the center, large */
  readout: string;
  /** small caption under the readout */
  unit?: string;
  /** SVG viewBox height in real pixels */
  height?: number;
  /** Cap on rendered width — matches the mockup's `.dial-svg { max-width: 380px }` so dials don't bloat on wide cards. Set 0 to remove cap. */
  maxWidth?: number;
  /** Override the loading/empty/partial/error wrapper (defaults to "ready"). */
  chartState?: ChartState;
  /** Custom label for the empty/error copy. */
  label?: string;
};

const STATE_COLOR: Record<DialState, string> = {
  ok: "var(--d-finance)",
  warn: "#b8761f",
  alert: "var(--d-ops)",
};

export function Dial({
  value,
  min,
  max,
  zones = [],
  ticks = [],
  state = "ok",
  readout,
  unit,
  height = 240,
  maxWidth = 380,
  chartState = "ready",
  label = "Dial",
}: Props) {
  const { ref, width: VBW } = useChartSize({ min: 280, fallback: 380 });
  const reduce = usePrefersReducedMotion();
  const [swept, setSwept] = useState(false);

  // Geometry. Center horizontally; the arc starts at left padding and ends at right padding.
  const PAD = 50;
  const cx = VBW / 2;
  const arcRadius = Math.min((VBW - 2 * PAD) / 2, height - 50);
  const cy = height - 50;

  /** Convert pct (0..100) to point on the arc */
  const pctToPoint = (pct: number) => {
    // 0% = left (angle 180°), 100% = right (angle 0°)
    const theta = Math.PI * (1 - pct / 100);
    return {
      x: cx + arcRadius * Math.cos(theta),
      y: cy - arcRadius * Math.sin(theta),
    };
  };

  /** SVG arc path between two pcts */
  const arcPath = (a: number, b: number) => {
    const p1 = pctToPoint(a);
    const p2 = pctToPoint(b);
    return `M ${p1.x.toFixed(2)} ${p1.y.toFixed(2)} A ${arcRadius} ${arcRadius} 0 0 1 ${p2.x.toFixed(2)} ${p2.y.toFixed(2)}`;
  };

  // Needle target % within [min, max]. Needle stops short of the arc (~88% of radius)
  // so it reads as a dial, not a chord touching the colored band.
  const clampedValue = Math.max(min, Math.min(max, value));
  const valuePct = ((clampedValue - min) / (max - min)) * 100;
  const needleR = arcRadius * 0.88;
  const needleTheta = Math.PI * (1 - valuePct / 100);
  const needleEnd = {
    x: cx + needleR * Math.cos(needleTheta),
    y: cy - needleR * Math.sin(needleTheta),
  };

  // Animated needle sweep on mount
  useEffect(() => {
    if (reduce) {
      setSwept(true);
      return;
    }
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setSwept(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  const needleColor = STATE_COLOR[state];
  const readoutColor =
    state === "ok" ? "var(--ink)" : state === "alert" ? "var(--d-ops)" : "#b8761f";
  const ARC_W = 22;

  const hostStyle: React.CSSProperties = {
    width: "100%",
    maxWidth: maxWidth > 0 ? `${maxWidth}px` : undefined,
    marginLeft: "auto",
    marginRight: "auto",
  };

  return (
    <div ref={ref} style={hostStyle}>
      <ChartStates state={chartState} height={height} label={label}>
      <svg viewBox={`0 0 ${VBW} ${height}`} className="mg-dial-svg" style={{ display: "block", width: "100%", height: "auto" }}>
        {/* base arc */}
        <path d={arcPath(0, 100)} fill="none" stroke="rgba(0,0,0,0.06)" strokeWidth={ARC_W} strokeLinecap="butt" />

        {/* zones painted in paint order */}
        {zones.map((z, i) => (
          <path
            key={i}
            d={arcPath(z.startPct, z.endPct)}
            fill="none"
            stroke={z.color}
            strokeWidth={ARC_W}
            strokeLinecap="butt"
          />
        ))}

        {/* tick marks — short stub extending INWARD from the arc edge toward center */}
        {ticks.map((t, i) => {
          const p = pctToPoint(t.pct);
          const theta = Math.PI * (1 - t.pct / 100);
          // outer = on the arc center line; inner = closer to dial center
          const outer = {
            x: cx + arcRadius * Math.cos(theta),
            y: cy - arcRadius * Math.sin(theta),
          };
          const inner = {
            x: cx + (arcRadius - 18) * Math.cos(theta),
            y: cy - (arcRadius - 18) * Math.sin(theta),
          };
          return (
            <g key={i}>
              <line
                x1={inner.x}
                y1={inner.y}
                x2={outer.x}
                y2={outer.y}
                stroke={t.major ? "var(--ink-2)" : "var(--ink-3)"}
                strokeWidth={t.major ? 1.5 : 1}
                opacity={t.major ? 0.85 : 0.55}
              />
              {t.label && (
                <text
                  x={p.x}
                  y={p.y + (t.pct < 10 || t.pct > 90 ? 18 : -10)}
                  textAnchor="middle"
                  fontFamily="JetBrains Mono, monospace"
                  fontSize={11}
                  letterSpacing="0.1em"
                  fill="var(--ink-3)"
                  fontWeight={500}
                >
                  {t.label}
                </text>
              )}
            </g>
          );
        })}

        {/* needle — animated sweep from 0% to value */}
        <line
          x1={cx}
          y1={cy}
          x2={swept ? needleEnd.x : cx - arcRadius}
          y2={swept ? needleEnd.y : cy}
          stroke={needleColor}
          strokeWidth={3.5}
          strokeLinecap="round"
          style={{
            transition: "all .9s cubic-bezier(.4,.1,.2,1)",
          }}
        />

        {/* pivot ring + center */}
        <circle cx={cx} cy={cy} r={13} fill="none" stroke="rgba(0,0,0,0.1)" strokeWidth={1} />
        <circle cx={cx} cy={cy} r={9} fill={needleColor} />

        {/* center readout */}
        <text
          x={cx}
          y={cy - 40}
          textAnchor="middle"
          fontFamily="Inter, sans-serif"
          fontSize={44}
          fontWeight={300}
          fill={readoutColor}
          letterSpacing="-0.03em"
        >
          {readout}
        </text>
        {unit && (
          <text
            x={cx}
            y={cy - 20}
            textAnchor="middle"
            fontFamily="JetBrains Mono, monospace"
            fontSize={10}
            letterSpacing="0.16em"
            fill="var(--ink-3)"
            fontWeight={400}
            style={{ textTransform: "uppercase" }}
          >
            {unit.toUpperCase()}
          </text>
        )}
      </svg>
      </ChartStates>
    </div>
  );
}
