"use client";

/**
 * Magellan SparkLine — small responsive line chart with optional area fill
 * and end dot. Reduced-motion-aware draw-in. Used for channel-tile trends,
 * MER spark, Organic Saved spark, Cash trend.
 */

import { useEffect, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

type Props = {
  /** Y values, evenly spaced left→right */
  values: number[];
  /** stroke color */
  color: string;
  /** if set, fill under the line with this color (use semi-transparent) */
  area?: string;
  /** if true, draws an emphasized dot on the last point */
  endDot?: boolean;
  /** SVG height in px (drives intrinsic ratio) */
  height?: number;
  /** stroke width */
  strokeWidth?: number;
  /** vertical inset so the line doesn't hug the edges */
  padY?: number;
  /** state-of-data wrapper (§2 rule 5). Defaults to "ready". */
  chartState?: ChartState;
  /** label used in empty/error copy. */
  label?: string;
};

export function SparkLine({
  values,
  color,
  area,
  endDot = false,
  height = 28,
  strokeWidth = 1.5,
  padY = 4,
  chartState = "ready",
  label = "Spark",
}: Props) {
  const { ref, width: VBW } = useChartSize({ min: 40, fallback: 80, debounceMs: 60 });
  const reduce = usePrefersReducedMotion();
  const [drawn, setDrawn] = useState(false);
  const n = values.length;

  // Normalize Y to [padY, height-padY] (top→bottom in SVG, so invert)
  const min = Math.min(...values);
  const max = Math.max(...values);
  const span = max - min || 1;
  const X = (i: number) => (VBW * i) / Math.max(1, n - 1);
  const Y = (v: number) => height - padY - ((v - min) / span) * (height - 2 * padY);

  const points = values.map((v, i) => `${X(i).toFixed(2)},${Y(v).toFixed(2)}`).join(" ");
  const areaPoints = points + ` ${VBW},${height} 0,${height}`;
  const lineLen = VBW + 50;

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce, VBW]);

  return (
    <div ref={ref} style={{ width: "100%" }}>
      <ChartStates state={chartState} height={height} label={label}>
      <svg
        viewBox={`0 0 ${VBW} ${height}`}
        style={{ display: "block", width: "100%", height: `${height}px` }}
      >
        {area && <polygon points={areaPoints} fill={area} />}
        <polyline
          points={points}
          fill="none"
          stroke={color}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          strokeLinejoin="round"
          style={{
            strokeDasharray: lineLen,
            strokeDashoffset: drawn ? 0 : lineLen,
            transition: "stroke-dashoffset 1.1s cubic-bezier(.4,.1,.2,1)",
          }}
        />
        {endDot && n > 0 && (
          <>
            <circle cx={X(n - 1)} cy={Y(values[n - 1])} r={5} fill={color} opacity={0.18} />
            <circle cx={X(n - 1)} cy={Y(values[n - 1])} r={2.5} fill={color} />
          </>
        )}
      </svg>
      </ChartStates>
    </div>
  );
}
