"use client";

/**
 * <ChartStates> — site-wide state wrapper for any chart.
 *
 * Per CHART-STANDARD.md §2 rule 5 and §3:
 *   Every chart routes through this primitive so a new account, a missing
 *   series, an in-flight fetch, or an API error all render *inside the frame*.
 *   A static SVG can only ever show "perfect" — this is what makes the
 *   instrument feel designed when data isn't there.
 *
 * Usage:
 *
 *   <ChartStates state={state} height={260} label="Cash projection">
 *     <svg .../>  // ready state — only rendered when state is "ready" or absent
 *   </ChartStates>
 *
 * For partial: pass a `partialNote` prop and the ready content still
 * renders, with a quiet note overlay (§7.2 partial: render what you have).
 */

import type React from "react";

export type ChartState = "ready" | "loading" | "empty" | "partial" | "error";

export interface ChartStatesProps {
  /** Current state. Defaults to "ready" — pass it through from your chart's `state` prop. */
  state?: ChartState;
  /** Height of the chart area in px (drives the placeholder box). */
  height: number;
  /** Short label/kicker — used in empty + error copy ("no Cash data yet"). */
  label?: string;
  /** Override copy for the empty state. Defaults to a calm "no data yet" message. */
  emptyCopy?: React.ReactNode;
  /** Override copy for the partial state. */
  partialNote?: React.ReactNode;
  /** Override copy for the error state. */
  errorCopy?: React.ReactNode;
  /** Ready content — the actual <svg>. Only rendered when state is "ready" or "partial". */
  children: React.ReactNode;
}

export function ChartStates({
  state = "ready",
  height,
  label,
  emptyCopy,
  partialNote,
  errorCopy,
  children,
}: ChartStatesProps) {
  if (state === "ready") return <>{children}</>;

  if (state === "partial") {
    return (
      <div className="chart-states partial">
        {children}
        <div className="chart-states-partial-note">
          <span className="dot" />
          {partialNote ?? "Some series unavailable · showing verified data only"}
        </div>
      </div>
    );
  }

  if (state === "loading") {
    return (
      <div
        className="chart-states loading"
        style={{ height }}
        role="status"
        aria-live="polite"
        aria-label={label ? `${label} loading` : "Chart loading"}
      >
        <div className="cs-axis" />
        <div className="cs-axis" />
        <div className="cs-axis" />
      </div>
    );
  }

  if (state === "empty") {
    return (
      <div className="chart-states empty" style={{ height }}>
        <div className="cs-stack">
          <span className="cs-eyebrow">No data yet</span>
          <span className="cs-body">
            {emptyCopy ?? (
              <>
                {label ? `${label} will populate ` : "This chart will populate "}
                once a source is connected.
              </>
            )}
          </span>
        </div>
      </div>
    );
  }

  // error
  return (
    <div className="chart-states error" style={{ height }} role="alert">
      <div className="cs-stack">
        <span className="cs-eyebrow">Couldn&rsquo;t load</span>
        <span className="cs-body">
          {errorCopy ?? "Try again in a moment — the connection will retry automatically."}
        </span>
      </div>
    </div>
  );
}
