"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState as CanonicalChartState } from "@/components/charts/_kit/ChartStates";

/* ════════════════════════════════════════════════════════════════════════
   GrowthSuperChart — "Is your growth working?"
   The signature Overview instrument: revenue vs efficiency (MER) over 12 months,
   with a last-year ghost line. Answers in one glance: are we growing vs last
   year, and are we EARNING the growth (MER holding) or BUYING it (MER falling)?
   ════════════════════════════════════════════════════════════════════════ */

export interface GrowthPoint {
  month: string;
  /** $K this year */
  revenue: number;
  /** marketing efficiency ratio (revenue ÷ ad spend), × */
  mer: number;
  /** $K same month last year */
  lastYearRevenue: number;
}

/** Re-export the canonical kit ChartState for back-compat with importers. */
export type ChartState = CanonicalChartState;

export interface GrowthSuperChartProps {
  /** Omit to use sampleGrowthData. Pass live data when ready. */
  data?: GrowthPoint[];
  /** Render state — see Chart Standard §2 rule 5 + §7.2 */
  state?: ChartState;
  /** Hero figure shown in the header (latest revenue, $K). Defaults to last data point. */
  heroRevenue?: number;
  /** YoY % delta shown next to the hero. Computed from data if omitted. */
  yoyPct?: number;
  /** Fires when the user clicks the NOW marker — e.g. open Bridge / Study. */
  onNowClick?: () => void;
}

/** Sample data — typed identically to the real shape so the API swap is one line. */
export const sampleGrowthData: GrowthPoint[] = [
  { month: "Mar", revenue: 182, mer: 4.6, lastYearRevenue: 150 },
  { month: "Apr", revenue: 196, mer: 4.5, lastYearRevenue: 158 },
  { month: "May", revenue: 210, mer: 4.6, lastYearRevenue: 168 },
  { month: "Jun", revenue: 228, mer: 4.4, lastYearRevenue: 176 },
  { month: "Jul", revenue: 236, mer: 4.5, lastYearRevenue: 180 },
  { month: "Aug", revenue: 248, mer: 4.3, lastYearRevenue: 188 },
  { month: "Sep", revenue: 242, mer: 4.4, lastYearRevenue: 184 },
  { month: "Oct", revenue: 266, mer: 4.2, lastYearRevenue: 196 },
  { month: "Nov", revenue: 288, mer: 3.8, lastYearRevenue: 210 },
  { month: "Dec", revenue: 272, mer: 3.6, lastYearRevenue: 206 },
  { month: "Jan", revenue: 298, mer: 4.2, lastYearRevenue: 214 },
  { month: "Feb", revenue: 314, mer: 4.4, lastYearRevenue: 223 },
];

/* fixed geometry (height is constant; width comes from useChartSize) */
const VBH = 380;
const T = 30;
const B = 300;
const PAD_L = 14;
const PAD_R = 14;
const REV_MAX = 360;
const REV_MIN = 120;
const MER_MAX = 5.2;
const MER_MIN = 3.0;

const C = {
  revenue: "#1D9E75",
  mer: "#E8932D",
  merLabel: "#b06a1a",
  ghost: "#8a8d94",
  compass: "#5B7CB0",
  gold: "#b88a2a",
  ink: "#15171c",
  ink2: "#3d4047",
  ink3: "#8a8d94",
};

export function GrowthSuperChart({
  data = sampleGrowthData,
  state = "ready",
  heroRevenue,
  yoyPct,
  onNowClick,
}: GrowthSuperChartProps) {
  const { ref, width } = useChartSize({ min: 640, fallback: 1000 });
  const reduce = usePrefersReducedMotion();
  const containerRef = useRef<HTMLDivElement | null>(null);
  const svgRef = useRef<SVGSVGElement | null>(null);
  const [hover, setHover] = useState<number | null>(null);

  // Non-ready (or empty data) → route through canonical <ChartStates> so the
  // page chrome stays intact. The wrapper handles loading/empty/partial/error
  // styling site-wide (Chart Standard §3 + §7.2).
  if (state !== "ready" || data.length === 0) {
    const effective = state === "ready" && data.length === 0 ? "empty" : state;
    return (
      <div className="gx-chart-area" ref={containerRef} style={{ minHeight: 380 }}>
        <ChartStates
          state={effective}
          height={380}
          label="Growth"
          emptyCopy="No revenue data yet — connect a source to see growth."
          errorCopy="Couldn't load this chart. The connection will retry automatically."
        >
          {/* unreachable while non-ready — wrapper only renders children for ready/partial */}
          <span />
        </ChartStates>
      </div>
    );
  }

  const n = data.length;
  const last = data[n - 1];
  const resolvedHero = heroRevenue ?? last.revenue;
  const resolvedYoy =
    yoyPct ?? Math.round((last.revenue / last.lastYearRevenue - 1) * 100);

  const L = PAD_L;
  const R = width - PAD_R;

  const X = (i: number) => L + ((R - L) * i) / (n - 1);
  const Yr = (v: number) => B - ((v - REV_MIN) / (REV_MAX - REV_MIN)) * (B - T);
  const Ym = (v: number) => B - ((v - MER_MIN) / (MER_MAX - MER_MIN)) * (B - T);

  const geom = useMemo(() => {
    const rxs = data.map((_, i) => X(i));
    const rys = data.map((d) => Yr(d.revenue));
    const lys = data.map((d) => Yr(d.lastYearRevenue));
    const mys = data.map((d) => Ym(d.mer));
    return { rxs, rys, lys, mys };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [width, data]);

  const { rxs, rys, lys, mys } = geom;
  const nx = X(n - 1);
  const ny = Yr(last.revenue);

  /* count-up hero */
  const [heroVal, setHeroVal] = useState(reduce ? resolvedHero : 0);
  useEffect(() => {
    if (reduce) {
      setHeroVal(resolvedHero);
      return;
    }
    let raf = 0;
    const t0 = performance.now();
    const tick = (t: number) => {
      const p = Math.min(1, (t - t0) / 1000);
      const e = 1 - Math.pow(1 - p, 3);
      setHeroVal(resolvedHero * e);
      if (p < 1) raf = requestAnimationFrame(tick);
      else setHeroVal(resolvedHero);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [resolvedHero, reduce]);

  /* one-shot line draw-in */
  const [drawn, setDrawn] = useState(reduce);
  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    const id = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(id);
  }, [reduce]);

  /* hover */
  const handleMove = (e: React.MouseEvent) => {
    const svg = svgRef.current;
    if (!svg) return;
    const rb = svg.getBoundingClientRect();
    const sc = rb.width / width;
    const mx = (e.clientX - rb.left) / sc;
    let bi = 0;
    let bd = Infinity;
    for (let i = 0; i < n; i++) {
      const d = Math.abs(X(i) - mx);
      if (d < bd) {
        bd = d;
        bi = i;
      }
    }
    setHover(bi);
  };

  const gridRev = [120, 180, 240, 300, 360];
  const merTicks = [3.5, 4.5, 5.2];
  const xLabelIdx = data.map((_, i) => i).filter((i) => i % 2 === 0 || i === n - 1);

  const polyPoints = (xs: number[], ys: number[]) =>
    xs.map((x, i) => `${x},${ys[i]}`).join(" ");

  const lineLen = Math.max(R - L, 1) * 1.4;

  return (
    <div className="gx-chart-area" ref={containerRef}>
      <div ref={ref} style={{ width: "100%" }}>
        <svg
          ref={svgRef}
          viewBox={`0 0 ${width} ${VBH}`}
          style={{ display: "block", width: "100%", height: VBH, overflow: "visible" }}
          onMouseMove={handleMove}
          onMouseLeave={() => setHover(null)}
        >
          <defs>
            <linearGradient id="gxArea" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={C.revenue} stopOpacity={0.16} />
              <stop offset="100%" stopColor={C.revenue} stopOpacity={0.01} />
            </linearGradient>
          </defs>

          {/* gridlines + left axis labels */}
          {gridRev.map((v) => {
            const y = Yr(v);
            return (
              <g key={`g${v}`}>
                <line x1={L} y1={y} x2={R} y2={y} stroke="rgba(0,0,0,0.05)" strokeWidth={1} />
                <line x1={L} y1={y} x2={L + 8} y2={y} stroke={C.ink} strokeWidth={1.3} opacity={0.3} />
                {v > 120 && (
                  <text
                    x={L + 4}
                    y={y - 5}
                    fontFamily="'JetBrains Mono',monospace"
                    fontSize={13}
                    fontWeight={500}
                    letterSpacing="0.04em"
                    fill={C.ink2}
                  >
                    ${v}K
                  </text>
                )}
              </g>
            );
          })}

          {/* right MER axis labels */}
          {merTicks.map((v) => (
            <text
              key={`m${v}`}
              x={R - 4}
              y={Ym(v) - 5}
              textAnchor="end"
              fontFamily="'JetBrains Mono',monospace"
              fontSize={13}
              fontWeight={500}
              letterSpacing="0.04em"
              fill={C.merLabel}
            >
              {v.toFixed(1)}×
            </text>
          ))}

          <line x1={L} y1={B} x2={R} y2={B} stroke="rgba(0,0,0,0.14)" strokeWidth={1} />

          {/* healthy MER band */}
          <rect x={L} y={Ym(5.2)} width={R - L} height={Ym(4.0) - Ym(5.2)} fill={C.revenue} opacity={0.045} />
          <line x1={L} y1={Ym(4.0)} x2={R} y2={Ym(4.0)} stroke={C.revenue} strokeWidth={1} strokeDasharray="5 4" opacity={0.4} />
          <text
            x={L + 5}
            y={Ym(4.0) + 13}
            fontFamily="'JetBrains Mono',monospace"
            fontSize={9}
            fontWeight={600}
            letterSpacing="0.08em"
            fill="#1a8f6a"
            opacity={0.7}
          >
            HEALTHY MER · 4.0×+
          </text>

          {/* last-year ghost */}
          <polyline
            points={polyPoints(rxs, lys)}
            fill="none"
            stroke={C.ghost}
            strokeWidth={1.6}
            strokeDasharray="2 4"
            opacity={0.5}
            strokeLinejoin="round"
          />
          <text
            x={rxs[n - 1] - 6}
            y={lys[n - 1] + 16}
            textAnchor="end"
            fontFamily="'JetBrains Mono',monospace"
            fontSize={10}
            fontWeight={500}
            fill={C.ghost}
            opacity={0.7}
          >
            last yr ${last.lastYearRevenue}K
          </text>

          {/* area under revenue */}
          <polygon points={`${polyPoints(rxs, rys)} ${R},${B} ${L},${B}`} fill="url(#gxArea)" />

          {/* MER line */}
          <polyline
            points={polyPoints(rxs, mys)}
            fill="none"
            stroke={C.mer}
            strokeWidth={2.2}
            strokeLinejoin="miter"
            strokeLinecap="butt"
            strokeMiterlimit={10}
            style={
              reduce
                ? undefined
                : {
                    strokeDasharray: lineLen,
                    strokeDashoffset: drawn ? 0 : lineLen,
                    transition: "stroke-dashoffset 1.5s cubic-bezier(.4,.1,.2,1) .15s",
                  }
            }
          />
          {/* Revenue line on top */}
          <polyline
            points={polyPoints(rxs, rys)}
            fill="none"
            stroke={C.revenue}
            strokeWidth={2.8}
            strokeLinejoin="miter"
            strokeLinecap="butt"
            strokeMiterlimit={10}
            style={
              reduce
                ? undefined
                : {
                    strokeDasharray: lineLen,
                    strokeDashoffset: drawn ? 0 : lineLen,
                    transition: "stroke-dashoffset 1.5s cubic-bezier(.4,.1,.2,1) .15s",
                  }
            }
          />

          {/* square nodes (skip last — NOW marker replaces it) */}
          {data.slice(0, -1).map((_, i) => (
            <g key={`n${i}`}>
              <rect x={rxs[i] - 3} y={mys[i] - 3} width={6} height={6} rx={1.5} fill="#fff" stroke={C.mer} strokeWidth={1.6} />
              <rect x={rxs[i] - 3} y={rys[i] - 3} width={6} height={6} rx={1.5} fill="#fff" stroke={C.revenue} strokeWidth={1.6} />
            </g>
          ))}

          {/* x labels */}
          {xLabelIdx.map((i) => {
            const isNow = i === n - 1;
            return (
              <text
                key={`x${i}`}
                x={X(i)}
                y={B + 22}
                textAnchor="middle"
                fontFamily="'JetBrains Mono',monospace"
                fontSize={13}
                fontWeight={isNow ? 600 : 500}
                letterSpacing="0.06em"
                fill={isNow ? C.ink : C.ink2}
              >
                {data[i].month}
              </text>
            );
          })}

          {/* gold corner brackets */}
          {[
            `M${L},${T + 14} L${L},${T} L${L + 14},${T}`,
            `M${R - 14},${T} L${R},${T} L${R},${T + 14}`,
            `M${L},${B - 14} L${L},${B} L${L + 14},${B}`,
            `M${R - 14},${B} L${R},${B} L${R},${B - 14}`,
          ].map((d, i) => (
            <path key={`gb${i}`} d={d} stroke={C.gold} strokeWidth={1.4} fill="none" opacity={0.5} />
          ))}

          {/* NOW cluster — clickable */}
          <g onClick={onNowClick} style={{ cursor: onNowClick ? "pointer" : "default" }}>
            <line x1={nx} y1={ny} x2={nx} y2={B} stroke={C.compass} strokeWidth={1.2} strokeDasharray="2 3" opacity={0.6} />
            {!reduce &&
              [0, 1.1].map((off) => (
                <circle key={off} cx={nx} cy={ny} r={6} fill="none" stroke={C.compass} strokeWidth={1.8}>
                  <animate attributeName="r" values="6;22" dur="2.2s" begin={`${off}s`} repeatCount="indefinite" />
                  <animate attributeName="opacity" values="0.55;0" dur="2.2s" begin={`${off}s`} repeatCount="indefinite" />
                </circle>
              ))}
            <rect x={nx - 7} y={ny - 7} width={14} height={14} rx={1.5} fill={C.revenue} stroke="#fff" strokeWidth={1.8} />
            <rect x={nx - 80} y={ny - 50} width={74} height={26} rx={3} fill="#fffdf8" stroke="rgba(184,138,42,0.8)" strokeWidth={0.8} />
            <rect x={nx - 80} y={ny - 50} width={3} height={26} rx={1} fill={C.compass} />
            <text x={nx - 41} y={ny - 33} textAnchor="middle" fontFamily="Inter,sans-serif" fontSize={14} fontWeight={600} fill={C.ink}>
              ${Math.round(heroVal)}K
            </text>
          </g>

          {/* crosshair (hover) */}
          {hover !== null && (
            <g>
              <line x1={X(hover)} y1={T} x2={X(hover)} y2={B} stroke={C.compass} strokeWidth={1} strokeDasharray="3 3" opacity={0.7} />
              <rect x={X(hover) - 6.5} y={Yr(data[hover].revenue) - 6.5} width={13} height={13} rx={1.5} fill="#fff" stroke={C.revenue} strokeWidth={2.2} />
              <rect x={X(hover) - 6.5} y={Ym(data[hover].mer) - 6.5} width={13} height={13} rx={1.5} fill="#fff" stroke={C.mer} strokeWidth={2.2} />
            </g>
          )}
        </svg>
      </div>

      {/* HTML tooltip */}
      {hover !== null && (() => {
        const svgRect = svgRef.current?.getBoundingClientRect();
        if (!svgRect) return null;
        const sx = (X(hover) / width) * svgRect.width;
        const sy = (Yr(data[hover].revenue) / VBH) * VBH;
        const clamped = Math.max(70, Math.min(svgRect.width - 70, sx));
        const yoy = Math.round((data[hover].revenue / data[hover].lastYearRevenue - 1) * 100);
        return (
          <div className="gx-tip-react" style={{ left: clamped, top: sy }}>
            <div className="td">{data[hover].month}</div>
            <div className="row">
              <span className="sw" style={{ background: C.revenue }} />
              <span className="tv">${data[hover].revenue}K</span>
              <span className="tl">+{yoy}% YoY</span>
            </div>
            <div className="row">
              <span className="sw" style={{ background: C.mer }} />
              <span className="tv">{data[hover].mer.toFixed(1)}×</span>
              <span className="tl">MER</span>
            </div>
          </div>
        );
      })()}
    </div>
  );
}
